mapper.select:
SELECT COUNT(*)
FROM erp_sale_order
WHERE order_time >= #{todayStart}
  AND deleted = 0

      AND tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}

SELECT COUNT(*)
FROM erp_sale_out
WHERE out_time >= #{todayStart}
  AND deleted = 0

      AND tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}

SELECT DATE_FORMAT(out_time, '%Y-%m-%d') AS date, IFNULL(SUM(total_price), 0) AS value FROM erp_sale_out WHERE out_time >= #{startTime} AND deleted = 0
AND tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}
GROUP BY DATE_FORMAT(out_time, '%Y-%m-%d') ORDER BY date

SELECT COUNT(*)
FROM logistics_order
WHERE status = #{status}
  AND deleted = 0

      AND tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}

SELECT DATE_FORMAT(in_time, '%Y-%m-%d') AS date, IFNULL(SUM(total_price), 0) AS value FROM erp_purchase_in WHERE in_time >= #{startTime} AND deleted = 0
AND tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}
GROUP BY DATE_FORMAT(in_time, '%Y-%m-%d') ORDER BY date

SELECT DATE_FORMAT(c.create_time, '%Y-%m-%d') AS date, IFNULL(SUM(c.total_cost), 0) AS value FROM logistics_cost c WHERE c.create_time >= #{startTime} AND c.deleted = 0
AND c.tenant_id = ${@cn.iocoder.yudao.framework.tenant.core.context.TenantContextHolder@getTenantId()}
GROUP BY DATE_FORMAT(c.create_time, '%Y-%m-%d') ORDER BY date
